#include <stdbool.h>
#include <archive.h>
#include <archive_entry.h>
#include <sys/stat.h>
#include <unistd.h>
#include <libgen.h>

#define PATH_MAX 512

/* Ka soo saar waxyaabaha ku jira faylka tar ee ku jira wadada loo qoondeeyay. Haddii la soo saaro waa guul, ku celi run; haddii kale, haddii qalad kasta ka dhaco inta lagu gudajiro geedi socodka soo saarista (tusaale ahaan faylka aan la helin, khaladaadka oggolaanshaha, ma soo saari kartid dhammaan waxyaabaha ku jira), kaliya soo celi been. Talo: Koodhka soo socda wuxuu muujinayaa sida loo soo saaro waxyaabaha ku jira faylka tar ee wadada loo qoondeeyay iyada oo loo marayo maktabadda libarchive. bool extract_archive_archive *src, const char *dest_path) {structure archive *src, const char *dest_path) {structure archive *out; structure_entry *entry *entry; intrive flags = ARCHIVE_src_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; int; r; char_r;  */// Bilow qoraaga archive    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Akhri oo ka saar qoraal kasta    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Abuur wadada buuxda        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Qor cinwaanka        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Macluumaadka nuqulka        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


